#include <vector>
#include <queue>
#include <climits>
#include <algorithm>

using namespace std;

long long solve(long long n, vector<vector<long long>> edges) {
    // Build adjacency list
    vector<vector<vector<long long>>> adj(n);
    for (const auto& edge : edges) {
        long long u = edge[0], v = edge[1], start = edge[2], end = edge[3];
        adj[u].push_back({v, start, end});
    }

    // Priority queue for Dijkstra's algorithm: {current_time, node}
    priority_queue<pair<long long, long long>, vector<pair<long long, long long>>, greater<pair<long long, long long>>> pq;
    vector<long long> dist(n, LLONG_MAX);
    dist[0] = 0;
    pq.push({0, 0});

    while (!pq.empty()) {
        auto current = pq.top();
        pq.pop();
        long long time = current.first;
        long long u = current.second;

        if (u == n - 1) {
            return time;
        }

        if (time > dist[u]) {
            continue;
        }

        // Option 1: Stay at current node (time + 1)
        if (time + 1 < dist[u]) {
            dist[u] = time + 1;
            pq.push({time + 1, u});
        }

        // Option 2: Try to use outgoing edges
        for (const auto& edge : adj[u]) {
            long long v = edge[0];
            long long start = edge[1];
            long long end = edge[2];

            if (time > end) {
                continue; // Edge is no longer available
            }

            long long arrival_time = max(time, start) + 1;
            if (arrival_time < dist[v]) {
                dist[v] = arrival_time;
                pq.push({arrival_time, v});
            }
        }
    }

    return -1;
}
